param([Parameter(Mandatory=$true)][string]$RepoRoot)
$ErrorActionPreference="Stop"
Set-StrictMode -Version Latest
function Die([string]$m){ throw $m }
function Utf8NoBom { New-Object System.Text.UTF8Encoding($false) }
function WriteUtf8NoBomLf([string]$Path,[string]$Content){
  $parent = Split-Path -Parent $Path
  if($parent -and -not (Test-Path -LiteralPath $parent)){ New-Item -ItemType Directory -Force -Path $parent | Out-Null }
  $lf = $Content.Replace("`r`n","`n")
  if(-not $lf.EndsWith("`n")){ $lf += "`n" }
  [IO.File]::WriteAllText($Path,$lf,(Utf8NoBom))
}
function ParseGate([string]$Path){ [ScriptBlock]::Create((Get-Content -Raw -LiteralPath $Path -Encoding UTF8)) | Out-Null }
if(-not (Test-Path -LiteralPath $RepoRoot -PathType Container)){ Die ("MISSING_REPO: " + $RepoRoot) }
$ScriptsDir = Join-Path $RepoRoot "scripts"
New-Item -ItemType Directory -Force -Path $ScriptsDir | Out-Null
$LibPath  = Join-Path $ScriptsDir "_lib_neverlost_v1.ps1"
$MakePath = Join-Path $ScriptsDir "make_allowed_signers_v1.ps1"
$ShowPath = Join-Path $ScriptsDir "show_identity_v1.ps1"
$ts = Get-Date -Format "yyyyMMdd_HHmmss"
$BackupDir = Join-Path $ScriptsDir ("_neverlost_backup_forcefix_" + $ts)
New-Item -ItemType Directory -Force -Path $BackupDir | Out-Null
foreach($p in @($LibPath,$MakePath,$ShowPath)){ if(Test-Path -LiteralPath $p){ Copy-Item -LiteralPath $p -Destination (Join-Path $BackupDir ((Split-Path -Leaf $p)+".pre_forcefix")) -Force } }
$libText = "Set-StrictMode -Version Latest" + "`n" + "$ErrorActionPreference = \"Stop\"" + "`n" + "" + "`n" + "# StrictMode-safe + self-healing guard:" + "`n" + "# - never reads unset vars directly" + "`n" + "# - reloads/defines if marker is set but key functions are missing" + "`n" + "$nlVar = Get-Variable -Name NL_LIB_LOADED -Scope Global -ErrorAction SilentlyContinue" + "`n" + "$needLoad = $true" + "`n" + "if(($null -ne $nlVar) -and ($nlVar.Value -eq $true)){ $needLoad = $false }" + "`n" + "if(-not (Get-Command NL-WriteAllowedSigners -ErrorAction SilentlyContinue)){ $needLoad = $true }" + "`n" + "if(-not (Get-Command NL-GetDefaultPrincipalAndKey -ErrorAction SilentlyContinue)){ $needLoad = $true }" + "`n" + "if(-not (Get-Command NL-TrustBundlePath -ErrorAction SilentlyContinue)){ $needLoad = $true }" + "`n" + "" + "`n" + "if($needLoad){" + "`n" + "  $global:NL_LIB_LOADED = $true" + "`n" + "" + "`n" + "  function NL-Die([string]$m){ throw $m }" + "`n" + "  function NL-Utf8NoBom { New-Object System.Text.UTF8Encoding($false) }" + "`n" + "" + "`n" + "  function NL-WriteUtf8NoBomLf([string]$Path,[string]$Content){" + "`n" + "    $parent = Split-Path -Parent $Path" + "`n" + "    if($parent -and -not (Test-Path -LiteralPath $parent)){ New-Item -ItemType Directory -Force -Path $parent | Out-Null }" + "`n" + "    $lf = $Content.Replace(\"`r`n\",\"`n\")" + "`n" + "    if(-not $lf.EndsWith(\"`n\")){ $lf += \"`n\" }" + "`n" + "    [IO.File]::WriteAllText($Path,$lf,(NL-Utf8NoBom))" + "`n" + "  }" + "`n" + "" + "`n" + "  function NL-ReadTextUtf8([string]$Path){" + "`n" + "    if(-not (Test-Path -LiteralPath $Path)){ NL-Die (\"MISSING_FILE: \" + $Path) }" + "`n" + "    (Get-Content -LiteralPath $Path -Raw -Encoding UTF8).Replace(\"`r`n\",\"`n\")" + "`n" + "  }" + "`n" + "" + "`n" + "  function NL-ReadJson([string]$Path){" + "`n" + "    $raw = NL-ReadTextUtf8 $Path" + "`n" + "    try { $raw | ConvertFrom-Json } catch { NL-Die (\"JSON_PARSE_FAIL: \" + $Path + \" :: \" + $_.Exception.Message) }" + "`n" + "  }" + "`n" + "" + "`n" + "  function NL-Sha256HexFile([string]$Path){" + "`n" + "    if(-not (Test-Path -LiteralPath $Path)){ NL-Die (\"MISSING_FILE: \" + $Path) }" + "`n" + "    (Get-FileHash -Algorithm SHA256 -LiteralPath $Path).Hash.ToLowerInvariant()" + "`n" + "  }" + "`n" + "" + "`n" + "  function NL-ValidatePrincipal([string]$Principal){" + "`n" + "    if([string]::IsNullOrWhiteSpace($Principal)){ NL-Die \"PRINCIPAL_EMPTY\" }" + "`n" + "    if($Principal -notmatch \"^single-tenant\/[a-z0-9_\-\.]+\/authority\/[a-z0-9_\-\.]+$\"){ NL-Die (\"PRINCIPAL_INVALID: \" + $Principal) }" + "`n" + "  }" + "`n" + "" + "`n" + "  function NL-TrustBundlePath([string]$RepoRoot){ Join-Path $RepoRoot \"proofs\trust\trust_bundle.json\" }" + "`n" + "  function NL-AllowedSignersPath([string]$RepoRoot){ Join-Path $RepoRoot \"proofs\trust\allowed_signers\" }" + "`n" + "" + "`n" + "  function NL-HasProperty([object]$Obj, [string]$Name){" + "`n" + "    if($null -eq $Obj){ return $false }" + "`n" + "    if($null -eq $Obj.PSObject){ return $false }" + "`n" + "    $m = @(@($Obj.PSObject.Properties.Match($Name)))" + "`n" + "    return ($m.Count -gt 0)" + "`n" + "  }" + "`n" + "" + "`n" + "  function NL-NormalizeKeys([object]$PrincipalRecord){" + "`n" + "    if(NL-HasProperty $PrincipalRecord \"keys\"){ return @(@($PrincipalRecord.keys)) }" + "`n" + "    return @($PrincipalRecord)" + "`n" + "  }" + "`n" + "" + "`n" + "  function NL-LoadTrustBundle([string]$RepoRoot){" + "`n" + "    $p  = NL-TrustBundlePath $RepoRoot" + "`n" + "    $tb = NL-ReadJson $p" + "`n" + "    if($null -eq $tb.schema -or [string]$tb.schema -ne \"neverlost.trust_bundle.v1\"){ NL-Die (\"TRUST_BUNDLE_SCHEMA_INVALID: expected neverlost.trust_bundle.v1 :: \" + $p) }" + "`n" + "    $principals = @(@($tb.principals))" + "`n" + "    if($principals.Count -lt 1){ NL-Die (\"TRUST_BUNDLE_NO_PRINCIPALS: \" + $p) }" + "`n" + "    foreach($pr in $principals){" + "`n" + "      $pname = [string]$pr.principal" + "`n" + "      NL-ValidatePrincipal $pname" + "`n" + "      $keys = @(NL-NormalizeKeys $pr)" + "`n" + "      if($keys.Count -lt 1){ NL-Die (\"TRUST_BUNDLE_PRINCIPAL_NO_KEYS: \" + $pname) }" + "`n" + "      foreach($k in $keys){" + "`n" + "        if([string]::IsNullOrWhiteSpace([string]$k.key_id)){ NL-Die (\"KEY_ID_EMPTY: \" + $pname) }" + "`n" + "        if([string]::IsNullOrWhiteSpace([string]$k.pubkey)){ NL-Die (\"PUBKEY_EMPTY: \" + $pname + \"/\" + [string]$k.key_id) }" + "`n" + "        $nss = @(@($k.namespaces))" + "`n" + "        if($nss.Count -lt 1){ NL-Die (\"NAMESPACES_EMPTY: \" + $pname + \"/\" + [string]$k.key_id) }" + "`n" + "      }" + "`n" + "    }" + "`n" + "    $tb" + "`n" + "  }" + "`n" + "" + "`n" + "  function NL-GetDefaultPrincipalAndKey([string]$RepoRoot){" + "`n" + "    $tb = NL-LoadTrustBundle $RepoRoot" + "`n" + "    $pr = @(@($tb.principals))[0]" + "`n" + "    $k  = @(NL-NormalizeKeys $pr)[0]" + "`n" + "    [pscustomobject]@{ principal=[string]$pr.principal; key_id=[string]$k.key_id; pubkey=[string]$k.pubkey }" + "`n" + "  }" + "`n" + "" + "`n" + "  function NL-DeriveAllowedSignersText([object]$TrustBundle){" + "`n" + "    $lines = New-Object System.Collections.Generic.List[string]" + "`n" + "    foreach($pr in @(@($TrustBundle.principals))){" + "`n" + "      $principal = [string]$pr.principal" + "`n" + "      foreach($k in @(NL-NormalizeKeys $pr)){" + "`n" + "        $pub = [string]$k.pubkey" + "`n" + "        foreach($ns in @(@($k.namespaces))){" + "`n" + "          $ns2 = [string]$ns" + "`n" + "          if([string]::IsNullOrWhiteSpace($ns2)){ NL-Die (\"NAMESPACE_EMPTY: \" + $principal) }" + "`n" + "          $lines.Add((\"{0} {1} {2}\" -f $principal,$ns2,$pub))" + "`n" + "        }" + "`n" + "      }" + "`n" + "    }" + "`n" + "    $sorted = @($lines.ToArray() | Sort-Object)" + "`n" + "    (($sorted -join \"`n\") + \"`n\")" + "`n" + "  }" + "`n" + "" + "`n" + "  function NL-WriteAllowedSigners([string]$RepoRoot){" + "`n" + "    $tb  = NL-LoadTrustBundle $RepoRoot" + "`n" + "    $out = NL-AllowedSignersPath $RepoRoot" + "`n" + "    $txt = NL-DeriveAllowedSignersText $tb" + "`n" + "    NL-WriteUtf8NoBomLf $out $txt" + "`n" + "    $out" + "`n" + "  }" + "`n" + "}"
WriteUtf8NoBomLf $LibPath ($libText + "`n")
ParseGate $LibPath
$makeText = "param([Parameter(Mandatory=$true)][string]$RepoRoot)" + "`n" + "$ErrorActionPreference=\"Stop\"" + "`n" + "Set-StrictMode -Version Latest" + "`n" + "$thisDir = Split-Path -Parent $MyInvocation.MyCommand.Path" + "`n" + "$libPath = Join-Path $thisDir \"_lib_neverlost_v1.ps1\"" + "`n" + "if(-not (Test-Path -LiteralPath $libPath)){ throw (\"LIB_MISSING: \" + $libPath) }" + "`n" + "# Hard reset poisoned state (safe even if absent)" + "`n" + "Remove-Variable -Name NL_LIB_LOADED -Scope Global -ErrorAction SilentlyContinue" + "`n" + "Remove-Item -Path Function:\NL-* -ErrorAction SilentlyContinue" + "`n" + ". $libPath" + "`n" + "if(-not (Get-Command NL-WriteAllowedSigners -ErrorAction SilentlyContinue)){ throw (\"LIB_DOTSOURCE_FAILED: NL-WriteAllowedSigners :: \" + $libPath) }" + "`n" + "$out    = NL-WriteAllowedSigners $RepoRoot" + "`n" + "$tbPath = NL-TrustBundlePath $RepoRoot" + "`n" + "$asPath = NL-AllowedSignersPath $RepoRoot" + "`n" + "Write-Host \"OK: allowed_signers written deterministically\" -ForegroundColor Green" + "`n" + "Write-Host (\"trust_bundle:    {0}\" -f $tbPath) -ForegroundColor Cyan" + "`n" + "Write-Host (\"allowed_signers: {0}\" -f $asPath) -ForegroundColor Cyan" + "`n" + "Write-Host (\"trust_bundle_sha256:    {0}\" -f (NL-Sha256HexFile $tbPath)) -ForegroundColor DarkGray" + "`n" + "Write-Host (\"allowed_signers_sha256: {0}\" -f (NL-Sha256HexFile $asPath)) -ForegroundColor DarkGray"
WriteUtf8NoBomLf $MakePath ($makeText + "`n")
ParseGate $MakePath
$showText = "param([Parameter(Mandatory=$true)][string]$RepoRoot)" + "`n" + "$ErrorActionPreference=\"Stop\"" + "`n" + "Set-StrictMode -Version Latest" + "`n" + "$thisDir = Split-Path -Parent $MyInvocation.MyCommand.Path" + "`n" + "$libPath = Join-Path $thisDir \"_lib_neverlost_v1.ps1\"" + "`n" + "if(-not (Test-Path -LiteralPath $libPath)){ throw (\"LIB_MISSING: \" + $libPath) }" + "`n" + "# Hard reset poisoned state (safe even if absent)" + "`n" + "Remove-Variable -Name NL_LIB_LOADED -Scope Global -ErrorAction SilentlyContinue" + "`n" + "Remove-Item -Path Function:\NL-* -ErrorAction SilentlyContinue" + "`n" + ". $libPath" + "`n" + "if(-not (Get-Command NL-GetDefaultPrincipalAndKey -ErrorAction SilentlyContinue)){ throw (\"LIB_DOTSOURCE_FAILED: NL-GetDefaultPrincipalAndKey :: \" + $libPath) }" + "`n" + "$info = NL-GetDefaultPrincipalAndKey $RepoRoot" + "`n" + "Write-Host \"NeverLost Identity (v1)\" -ForegroundColor Green" + "`n" + "Write-Host (\"principal: {0}\" -f $info.principal) -ForegroundColor Cyan" + "`n" + "Write-Host (\"key_id:    {0}\" -f $info.key_id) -ForegroundColor Cyan" + "`n" + "Write-Host (\"pubkey:    {0}\" -f $info.pubkey) -ForegroundColor Cyan"
WriteUtf8NoBomLf $ShowPath ($showText + "`n")
ParseGate $ShowPath
Write-Host "OK: forcefix applied" -ForegroundColor Green
Write-Host ("backup_dir: {0}" -f $BackupDir) -ForegroundColor Cyan
Write-Host ("lib_sha256:  {0}" -f (Get-FileHash -Algorithm SHA256 -LiteralPath $LibPath).Hash.ToLowerInvariant()) -ForegroundColor DarkGray
Write-Host "OK: running make/show in-process..." -ForegroundColor Green
& $MakePath -RepoRoot $RepoRoot
& $ShowPath -RepoRoot $RepoRoot
